import{_ as a,o as e,c as r,ae as o}from"./chunks/framework.BeMCGcrk.js";const b=JSON.parse('{"title":"科技股每日分析 2026-06-29","description":"","frontmatter":{},"headers":[],"relativePath":"blog/2026-06-29-tech-stocks-daily.md","filePath":"blog/2026-06-29-tech-stocks-daily.md"}'),d={name:"blog/2026-06-29-tech-stocks-daily.md"};function h(s,t,n,l,i,p){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="科技股每日分析-2026-06-29" tabindex="-1">科技股每日分析 2026-06-29 <a class="header-anchor" href="#科技股每日分析-2026-06-29" aria-label="Permalink to &quot;科技股每日分析 2026-06-29&quot;">​</a></h1><h2 id="今日要闻" tabindex="-1">今日要闻 <a class="header-anchor" href="#今日要闻" aria-label="Permalink to &quot;今日要闻&quot;">​</a></h2><h3 id="阿里巴巴-baba-9988-hk" tabindex="-1">阿里巴巴 (BABA/9988.HK) <a class="header-anchor" href="#阿里巴巴-baba-9988-hk" aria-label="Permalink to &quot;阿里巴巴 (BABA/9988.HK)&quot;">​</a></h3><p><strong>辟谣首席科学家离职传闻</strong></p><p>6月14日，针对网传阿里首席科学家周靖人将离职的传闻，阿里巴巴回应称&quot;周靖人辞职&quot;纯属谣言。阿里方面表示将追究传播谣言者的法律责任。</p><p><strong>组织架构调整</strong></p><p>1月13日，阿里公布新一轮组织架构调整，涉及菜鸟网络、国际业务、云OS等部门。任命童文红为阿里巴巴集团首席人力官。</p><hr><h3 id="美团-3690-hk" tabindex="-1">美团 (3690.HK) <a class="header-anchor" href="#美团-3690-hk" aria-label="Permalink to &quot;美团 (3690.HK)&quot;">​</a></h3><p><strong>外卖平台补贴规范出台</strong></p><p>6月17日，《外卖平台补贴行为规范十条》征求意见稿发布，新华社、央视网、人民网同步播发。美团坚决拥护，将认真学习并积极配合落地。</p><p>美团表示，将持续优化计价、时长预估、路径规范等算法，落实取消超时扣款、改进服务分规则、算法协商恳谈等措施。</p><p><strong>一季度财报要点</strong></p><p>6月1日发布的Q1财报显示，随着餐饮外卖行业补贴持续优化，外卖竞争正逐步转向以效率和体验为核心的阶段。若竞争环境保持理性，叠加二季度旺季效应，预期Q2外卖UE持续改善。</p><hr><h3 id="小米-1810-hk" tabindex="-1">小米 (1810.HK) <a class="header-anchor" href="#小米-1810-hk" aria-label="Permalink to &quot;小米 (1810.HK)&quot;">​</a></h3><p><strong>增程式车型准入公示</strong></p><p>6月10日，工信部发布《道路机动车辆生产企业及产品公告》(第408批)，小米汽车科技有限公司拟办理准入变更，增加了增程式电动乘用车产品品种。这意味着小米将进入增程式SUV市场。</p><p><strong>泄密事件处理</strong></p><p>5月30日，小米发布《关于小米汽车相关恶意泄密及谣言的声明》，对3名违规员工予以辞退并永不录用，同时追究2名媒体人的泄密责任。</p><hr><h2 id="分析观点" tabindex="-1">分析观点 <a class="header-anchor" href="#分析观点" aria-label="Permalink to &quot;分析观点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>近期催化剂</th><th>风险点</th></tr></thead><tbody><tr><td>阿里</td><td>组织架构调整、AI投入</td><td>电商竞争加剧、监管政策</td></tr><tr><td>美团</td><td>补贴规范出台、竞争理性化</td><td>本地生活赛道持久战</td></tr><tr><td>小米</td><td>增程式新车上市</td><td>汽车产能与交付</td></tr></tbody></table><hr><p><em>发布时间：2026-06-29</em></p>',25)])])}const _=a(d,[["render",h]]);export{b as __pageData,_ as default};
